import { GoogleGenAI, GenerateContentResponse, Type } from "@google/genai";
import { FraudNews, GameRound } from "../types";

export const getAI = (customKey?: string) => {
  return new GoogleGenAI({ apiKey: customKey || (process.env.API_KEY as string) });
};

export async function fetchFraudNews(keywords: string[]): Promise<FraudNews[]> {
  const ai = getAI();
  const prompt = `搜寻关于这些关键词的最新诈骗和骗局新闻：${keywords.join(", ")}。

    要求：
    1. 请搜寻并提取 **20条** 不同的最新新闻。
    2. **过滤重复：** 如果发现手法高度相似的诈骗手段（例如针对同一银行的相同变体），请只保留最具代表性的一条，确保情报的多样性和广泛覆盖。
    3. 内容必须是最新的、真实发生的案例。

    请以 JSON 数组形式返回对象，结构如下：
    - title: 标题（中文）
    - summary: 诈骗手段的简短摘要（中文）
    - sourceUrl: 新闻来源 URL
    - date: 大致日期

    所有内容必须使用简体中文。`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              title: { type: Type.STRING },
              summary: { type: Type.STRING },
              sourceUrl: { type: Type.STRING },
              date: { type: Type.STRING },
            },
            required: ["title", "summary", "sourceUrl", "date"],
          },
        },
      },
    });

    return JSON.parse(response.text || "[]");
  } catch (error) {
    console.error("Error fetching news:", error);
    return [];
  }
}

export async function generateGameRounds(newsItems: FraudNews[]): Promise<GameRound[]> {
  const ai = getAI();
  const prompt = `根据提供的这20条真实诈骗新闻，生成 **10个** 用于模拟演练的游戏关卡。

    要求：
    1. 为每个关卡创建一个逼真的信息（短信）或电话脚本。
    2. 覆盖尽可能多的不同新闻点，不要只集中在少数几个案例上。
    3. 比例分配：大约 70% 为诈骗 (isFraud: true)，30% 为真实的正规通讯 (isFraud: false) 作为对照。
    4. **关键：** 为每个信息指定一个逼真的发送者 (sender)，例如：‘工商银行’、‘顺丰速运’、‘12381’、‘陈警官’、‘+86 138-xxxx-xxxx’等。

    新闻背景：${JSON.stringify(newsItems)}

    以 JSON 数组形式返回：
    - id: 唯一标识
    - sender: 发送者名称或号码（中文/数字，需符合真实逻辑）
    - content: 短信内容或电话对话脚本（中文，符合真实场景。如果是短信，请根据真实情况包含伪造链接或官方链接）
    - type: "sms" 或 "call"
    - isFraud: 布尔值，是否为诈骗
    - newsContext: 关联的新闻标题
    - explanation: 简短的理由，解释为什么这是或不是诈骗（中文）

    内容必须使用简体中文，风格要极其逼真。`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              id: { type: Type.STRING },
              sender: { type: Type.STRING },
              content: { type: Type.STRING },
              type: { type: Type.STRING },
              isFraud: { type: Type.BOOLEAN },
              newsContext: { type: Type.STRING },
              explanation: { type: Type.STRING },
            },
            required: ["id", "sender", "content", "type", "isFraud", "newsContext", "explanation"],
          },
        },
      },
    });

    return JSON.parse(response.text || "[]");
  } catch (error) {
    console.error("Error generating rounds:", error);
    return [];
  }
}

export async function generateHighQualityImage(prompt: string, size: "1K" | "2K" | "4K"): Promise<string> {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-image-preview',
    contents: { parts: [{ text: `A professional, high-quality asset for fraud awareness: ${prompt}. Cinematic lighting, highly detailed.` }] },
    config: {
      imageConfig: {
        aspectRatio: "1:1",
        imageSize: size,
      },
    },
  });

  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  throw new Error("No image data received");
}

export async function editImage(base64Image: string, editPrompt: string): Promise<string> {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [
        { inlineData: { data: base64Image.split(',')[1], mimeType: 'image/png' } },
        { text: editPrompt },
      ],
    },
  });

  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  throw new Error("No image data received from edit");
}

import React, { useState, useEffect, useRef } from 'react';
import { PhoneFrame } from './PhoneFrame';
import { Button } from './Button';
import { GameRound, FraudNews } from '../types';
import { ShieldCheck, ShieldAlert, Trophy, RotateCcw, User, Info } from 'lucide-react';

interface Props {
  news: FraudNews[];
  rounds: GameRound[];
  onRestart: () => void;
}

export const SimulatorGame: React.FC<Props> = ({ news, rounds, onRestart }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [score, setScore] = useState(0);
  const [feedback, setFeedback] = useState<{ correct: boolean; message: string } | null>(null);
  const [isAnimatingOut, setIsAnimatingOut] = useState(false);
  const [isAnimatingIn, setIsAnimatingIn] = useState(false);
  const audioRef = useRef<AudioContext | null>(null);

  const playNotificationSound = () => {
    try {
      if (!audioRef.current) {
        audioRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
      }
      const ctx = audioRef.current;
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();

      osc.type = 'sine';
      osc.frequency.setValueAtTime(880, ctx.currentTime);
      osc.frequency.exponentialRampToValueAtTime(440, ctx.currentTime + 0.2);

      gain.gain.setValueAtTime(0.1, ctx.currentTime);
      gain.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + 0.2);

      osc.connect(gain);
      gain.connect(ctx.destination);

      osc.start();
      osc.stop(ctx.currentTime + 0.2);
    } catch (e) {
      console.warn("Sound blocked by browser policy", e);
    }
  };

  useEffect(() => {
    if (currentIndex < rounds.length && !feedback) {
      setIsAnimatingIn(true);
      playNotificationSound();
      const timer = setTimeout(() => setIsAnimatingIn(false), 500);
      return () => clearTimeout(timer);
    }
  }, [currentIndex, rounds.length, feedback]);

  const handleGuess = (guess: boolean) => {
    if (isAnimatingOut || isAnimatingIn) return;
    const current = rounds[currentIndex];
    const correct = guess === current.isFraud;

    if (correct) setScore(s => s + 1);
    setFeedback({ correct, message: current.explanation });
  };

  const nextRound = () => {
    setIsAnimatingOut(true);
    setTimeout(() => {
      setFeedback(null);
      setCurrentIndex(i => i + 1);
      setIsAnimatingOut(false);
    }, 800);
  };

  const formatMessageContent = (text: string) => {
    // Regex to detect links (http, https, or common t.cn, bit.ly patterns)
    const urlPattern = /((https?:\/\/|www\.)[^\s]+|[\w-]+\.[a-z]{2,3}\/[^\s]+)/gi;
    const parts = text.split(urlPattern);

    return parts.map((part, i) => {
      if (part && part.match(urlPattern)) {
        return (
          <span key={part + i} className="message-link">
            {part}
          </span>
        );
      }
      return part;
    });
  };

  if (currentIndex >= rounds.length && rounds.length > 0) {
    return (
      <div className="max-w-md mx-auto text-center space-y-8 animate-slide-in">
        <div className="relative p-1">
            <div className="absolute inset-0 bg-gradient-to-r from-indigo-500 to-emerald-500 blur-xl opacity-20"></div>
            <div className="relative glass-morphism p-12 rounded-[3rem] border-2 border-indigo-500/20">
              <Trophy className="w-20 h-20 text-yellow-500 mx-auto mb-6" />
              <h2 className="text-3xl font-black mb-2">演练结束</h2>
              <div className="text-6xl font-black text-indigo-400 mb-4">{score} / {rounds.length}</div>
              <p className="text-slate-400 mb-8">
                {score === rounds.length ? "无懈可击！你是当之无愧的反诈专家。" : "表现不错。请保持警惕，保护好个人隐私。"}
              </p>
              <Button onClick={onRestart} className="w-full">
                <RotateCcw className="w-5 h-5" /> 重新部署情报
              </Button>
            </div>
        </div>
      </div>
    );
  }

  const currentRound = rounds[currentIndex];

  return (
    <div className="flex flex-col md:flex-row items-center justify-center gap-12 p-4">
      <div className="flex-1 max-w-lg space-y-6 hidden md:block">
        <h2 className="text-5xl font-black tracking-tighter uppercase italic text-indigo-500">
          反诈模拟室
        </h2>
        <p className="text-xl text-slate-400 leading-relaxed">
          诈骗分子的手段瞬息万变。为了适应长辈阅读，我们特意放大了字体并标注了危险链接。
        </p>
        <div className="flex gap-4">
          <div className="glass-morphism p-6 rounded-[2rem] flex-1 border-white/5">
            <div className="text-slate-500 text-xs uppercase font-bold mb-1">当前得分</div>
            <div className="text-3xl font-black">{score}</div>
          </div>
          <div className="glass-morphism p-6 rounded-[2rem] flex-1 border-white/5">
            <div className="text-slate-500 text-xs uppercase font-bold mb-1">进度</div>
            <div className="text-3xl font-black">{currentIndex + 1} <span className="text-slate-600 text-lg">/ {rounds.length}</span></div>
          </div>
        </div>
      </div>

      <div className="relative group">
        <PhoneFrame>
          <div className="flex flex-col h-full">
            {/* iOS Message Header - Dynamic Sender */}
            <div className="bg-[#f2f2f7]/80 backdrop-blur-md sticky top-0 px-4 py-3 flex flex-col items-center border-b border-black/5 z-10">
              <div className="w-10 h-10 bg-gray-300 rounded-full flex items-center justify-center mb-1 overflow-hidden">
                <User className="text-gray-500 w-6 h-6" />
              </div>
              <div className="text-[14px] font-bold text-gray-800 flex items-center gap-1">
                {currentRound?.sender || '未知号码'} <Info className="w-3.5 h-3.5 text-blue-500" />
              </div>
            </div>

            {/* iMessage Stream Area */}
            <div className="flex-1 p-3 flex flex-col gap-4 overflow-x-hidden">
              <div className="text-center">
                <span className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">
                  {currentRound?.type === 'sms' ? '短信' : '来电提醒'} · 今天
                </span>
              </div>

              <div className={`flex flex-col gap-1 transition-all duration-700 ${isAnimatingOut ? 'animate-car-zoom' : ''} ${isAnimatingIn ? 'animate-message-in' : ''}`}>
                <div className="imessage-bubble imessage-received ios-shadow text-xl md:text-2xl font-medium">
                  {currentRound && formatMessageContent(currentRound.content)}
                </div>
              </div>

              {feedback && !isAnimatingOut && (
                <div className="mt-8 flex flex-col items-center animate-slide-in px-4">
                  <div className={`w-14 h-14 rounded-full flex items-center justify-center mb-4 ${feedback.correct ? 'bg-emerald-500' : 'bg-rose-500'}`}>
                    {feedback.correct ? <ShieldCheck className="text-white w-8 h-8" /> : <ShieldAlert className="text-white w-8 h-8" />}
                  </div>
                  <h3 className={`text-xl font-bold mb-3 ${feedback.correct ? 'text-emerald-600' : 'text-rose-600'}`}>
                    {feedback.correct ? "判断正确" : "判断失误"}
                  </h3>
                  <div className="bg-white p-4 rounded-2xl shadow-sm border border-black/5 text-base text-gray-600 leading-relaxed italic mb-6">
                    {feedback.message}
                  </div>
                  <Button onClick={nextRound} className="w-full text-base rounded-full py-4 bg-black text-white hover:bg-gray-800">
                    下一关卡
                  </Button>
                </div>
              )}
            </div>

            {/* Action Buttons */}
            {!feedback && (
              <div className="px-4 pb-12 flex gap-4">
                <button 
                  onClick={() => handleGuess(true)}
                  className="flex-1 py-5 bg-rose-100 hover:bg-rose-200 text-rose-600 rounded-[2rem] font-black transition-all transform active:scale-95 border border-rose-200 shadow-sm"
                >
                  <ShieldAlert className="w-6 h-6 mx-auto mb-1" />
                  诈骗信息
                </button>
                <button 
                  onClick={() => handleGuess(false)}
                  className="flex-1 py-5 bg-emerald-100 hover:bg-emerald-200 text-emerald-600 rounded-[2rem] font-black transition-all transform active:scale-95 border border-emerald-200 shadow-sm"
                >
                  <ShieldCheck className="w-6 h-6 mx-auto mb-1" />
                  真实信息
                </button>
              </div>
            )}
          </div>
        </PhoneFrame>
        <div className="absolute -bottom-8 left-1/2 -translate-x-1/2 w-48 h-6 bg-white/5 blur-2xl rounded-full"></div>
      </div>
    </div>
  );
};

