    const urlPattern = /((https?:\/\/|www\.)[^\s]+|[\w-]+\.[a-z]{2,3}\/[^\s]+)/gi;
    const parts = text.split(urlPattern);
    return parts.map((part, i) => part && part.match(urlPattern) ? <span key={part + i} className="message-link font-bold">{part}</span> : part);
  };

