                      feedback.loss ? (
                        <div className="flex flex-col items-center animate-bounce">
                           <span className="bg-rose-600 text-white px-4 py-1.5 rounded-full font-black text-sm shadow-xl border-2 border-white/20">
                             资产损失 -¥{feedback.loss.toLocaleString()}
                           </span>
                           <TrendingDown className="text-rose-600 w-8 h-8 mt-1" />
                        </div>
                      ) : (
                        <div className="w-12 h-12 rounded-2xl flex items-center justify-center shadow-lg transform rotate-3 bg-slate-400">
                          <HelpCircle className="text-white w-8 h-8" />
                        </div>
                      )
                    )}
                  </div>

                  <div className={`text-center p-4 rounded-3xl border w-full ${feedback.correct ? 'bg-emerald-50 border-emerald-100' : 'bg-rose-50 border-rose-100 shadow-xl'}`}>
                     <h3 className={`text-xl font-black mb-1 ${feedback.correct ? 'text-emerald-700' : 'text-rose-700'}`}>
                        {getFeedbackTitle(feedback.correct, currentRound.isFraud)}
                     </h3>
                     <p className="text-gray-600 text-[11px] font-medium leading-relaxed italic">
                       {feedback.message}
                     </p>
                  </div>

                  <Button onClick={nextRound} className="w-full mt-6 py-4 rounded-full bg-black text-white text-sm">
                    继续演练
                  </Button>
                </div>
              )}
            </div>

            {/* User Interaction - Two small buttons in a row */}
            {!feedback && (
              <div className="px-4 pb-12 flex gap-3">
                <button 
                  onClick={() => handleGuess(true)}
                  className="flex-1 py-4 bg-rose-100 hover:bg-rose-200 text-rose-600 rounded-2xl font-black text-sm transition-all active:scale-95 border border-rose-200 shadow-sm flex flex-col items-center gap-1"
                >
                  <ShieldAlert className="w-5 h-5" />
                  这是诈骗
                </button>
                <button 
                  onClick={() => handleGuess(false)}
                  className="flex-1 py-4 bg-emerald-100 hover:bg-emerald-200 text-emerald-600 rounded-2xl font-black text-sm transition-all active:scale-95 border border-emerald-200 shadow-sm flex flex-col items-center gap-1"
                >
                  <ShieldCheck className="w-5 h-5" />
                  这是真实的
                </button>
              </div>
            )}
          </div>
        </PhoneFrame>
        {/* Shadow floor */}
        <div className="absolute -bottom-10 left-1/2 -translate-x-1/2 w-64 h-8 bg-black/40 blur-3xl rounded-full -z-10"></div>
      </div>
    </div>
  );
};
